query:
SELECT s.sceneIndex, s.status, s.taskId, s.videoUrl IS NOT NULL as hasVideo
FROM musicVideoScenes s
WHERE s.jobId = 510100
ORDER BY s.sceneIndex;

SELECT status, completedScenes, totalScenes FROM musicVideoJobs WHERE id = 510100;

